function CivicIndex({ openPaper }) {
  const [q, setQ] = React.useState('');
  const [track, setTrack] = React.useState('All');
  const wp = window.VW.whitepapers;
  const tracks = ['All', ...window.VW.tracks];
  const filtered = wp.filter(p => {
    if (track !== 'All' && p.track !== track) return false;
    if (q && !(p.title + ' ' + p.subtitle + ' ' + p.tags.join(' ')).toLowerCase().includes(q.toLowerCase())) return false;
    return true;
  });
  return (
    <div className="civic-index">
      <div className="head">
        <h1>Index of whitepapers</h1>
        <div className="count">{filtered.length} of {wp.length} · ordered by series</div>
      </div>
      <div className="filters">
        <div className="search">
          <input placeholder="Search titles, tags, authors…" value={q} onChange={e=>setQ(e.target.value)} />
        </div>
        <div className="chips">
          {tracks.map(t => (
            <div key={t} className={'chip ' + (track===t?'on':'')} onClick={()=>setTrack(t)}>{t}</div>
          ))}
        </div>
      </div>
      <table>
        <thead>
          <tr>
            <th>Vol. / №</th>
            <th>Title</th>
            <th>Track</th>
            <th>Read</th>
            <th>Status</th>
          </tr>
        </thead>
        <tbody>
          {filtered.map(p => (
            <tr key={p.id} onClick={()=>openPaper(p.id)}>
              <td className="num">{p.vol} · {p.num}</td>
              <td className="title">
                {p.title}
                <div className="sub">{p.subtitle}</div>
              </td>
              <td className="track">{p.track}</td>
              <td className="read">{p.reading_min} min · {p.pages}pp</td>
              <td className={'status ' + p.status.toLowerCase()}>{p.status}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

function CivicDetail({ paperId, setPage }) {
  const p = window.VW.whitepapers.find(w => w.id === paperId) || window.VW.whitepapers[0];
  const [active, setActive] = React.useState(0);
  const [tocOpen, setTocOpen] = React.useState(false);
  const onPickSection = (i) => { setActive(i); setTocOpen(false); };
  const bodyParas = [
    'The Government of Alberta operates a technology estate that has accumulated over thirty-five years of inheritance. The estate is heterogeneous, partially documented, and in places actively decaying. The rate of remediation has lagged the rate of accumulation for at least a decade. This paper argues that the gap can no longer be closed by hiring.',
    'A reasonable engineer, working competently on a representative legacy application, can produce on the order of one substantive remediation per week. Multiplied across the two thousand engineers presently employed across ministries, with realistic allowances for prioritization, on-call, and project overhead, the achievable throughput is roughly four thousand remediations per year against an installed base of approximately one hundred and forty thousand identified debt items.',
    'The arithmetic is straightforward and unwelcome. At current capacity, the province cannot reach steady-state. Debt accumulates faster than the workforce can pay it down. The carry grows against future budgets that must also fund healthcare and education.',
  ];

  // Related papers — three picked from the series (excluding this one).
  const related = window.VW.whitepapers
    .filter(w => w.id !== p.id)
    .slice(0, 4);

  return (
    <div className="civic-detail">
      <div className={'toc-overlay ' + (tocOpen ? 'show' : '')} onClick={()=>setTocOpen(false)}></div>
      <div className={'col-toc ' + (tocOpen ? 'open' : '')}>
        <button className="toc-close" onClick={()=>setTocOpen(false)} aria-label="Close TOC">CLOSE</button>
        <div className="back" onClick={()=>setPage('index')}>← Index</div>
        <div className="toc-head">In this paper</div>
        {p.sections.map((s, i) => (
          <div key={i} className={'toc-item ' + (i===active?'active':'')} onClick={()=>onPickSection(i)}>
            <span className="n">{s.n}</span>
            <span>{s.title}</span>
          </div>
        ))}
      </div>
      <div className="col-doc">
        <div className="doc-inner">
          <button className="civic-toc-toggle" onClick={()=>setTocOpen(true)} aria-label="Open table of contents">
            <span className="bars"><span></span><span></span><span></span></span>
            In this paper
          </button>
          <div className="doc-meta">
            <span>Whitepaper · <span className="num">№ {p.num}</span></span>
            <span>Vol. {p.vol}</span>
            <span>{p.track}</span>
            <span>{p.published}</span>
          </div>
          <h1 className="doc-title">{p.title}</h1>
          <div className="doc-sub">{p.subtitle}</div>

          <div className="doc-byline">
            <div className="item">
              <div className="l">Authored by</div>
              <div className="v">{p.authors.join(' · ')}</div>
            </div>
            <div className="item">
              <div className="l">Published</div>
              <div className="v">{p.published}</div>
            </div>
            <div className="item">
              <div className="l">Reading time</div>
              <div className="v">{p.reading_min} minutes · {p.pages} pp</div>
            </div>
            <div className="item">
              <div className="l">Status</div>
              <div className="v">{p.status}</div>
            </div>
          </div>

          <div className="abstract">
            <div className="lbl">Abstract</div>
            <p>{p.abstract}</p>
          </div>

          <div className="body">
            <h3><span className="n">{p.sections[0].n}</span><span>{p.sections[0].title}</span></h3>

            <div className="cd-sidenote">
              <div className="l">On scale</div>
              <div className="v">Alberta’s estate includes <strong>1,400 applications</strong> running on <strong>17 distinct platforms</strong>, with an average application age of <strong>14.3 years</strong>.</div>
            </div>
            <p><span className="dropcap">{bodyParas[0][0]}</span>{bodyParas[0].slice(1)}</p>
            <p>{bodyParas[1]}</p>

            <div className="cd-figure">
              <div className="fhdr">
                <span className="fno">FIG. 1.1</span>
                <span className="ftitle">Debt accumulation vs. remediation throughput, 2014–2025</span>
                <span className="src">Source: OCIO Estate Inventory</span>
              </div>
              <div className="fbody">
                <CivicMiniChart width={680} height={200} />
              </div>
              <div className="fcap">Debt items identified annually (solid, rust) against items remediated (dashed, navy). The widening gap is the subject of § 03 and § 04.</div>
            </div>

            <div className="pullquote">
              "Debt accumulates faster than the workforce can pay it down, and the carry grows against future budgets."
              <div className="cite">Velocity Working Group · § 01.3</div>
            </div>

            <p>{bodyParas[2]}</p>

            <h3><span className="n">{p.sections[1].n}</span><span>{p.sections[1].title}</span></h3>

            <div className="cd-keystat">
              <div>
                <span className="lbl">Annual carry, unbooked</span>
                <div className="big">$340M</div>
              </div>
              <div className="body-txt">
                The Carry Index places the province’s unrecognized maintenance burden at <strong>$340 million per year</strong>. The figure does not appear on any balance sheet, but it does appear in every ministry’s operating budget, distributed across line items whose original justifications no longer reflect the work being done.
              </div>
            </div>

            <p>Conventional hiring solves the wrong variable. The binding constraint is the rate at which an individual engineer develops the contextual understanding required to safely modify a legacy system. That understanding takes months to build, and the system carries thirty years of implicit business logic, undocumented dependencies, and knowledge that has long since left the organization.</p>
            <p>The cycle time from engineer-assigned to engineer-competent on a typical legacy application is measured in months. By the time competence is achieved, the system has often changed or the engineer has moved on. The province ends up with a workforce that is perpetually onboarding.</p>

            <div className="cd-related">
              <div className="lbl">Read next · cited in this paper</div>
              <div className="rlist">
                {related.slice(0, 4).map(r => (
                  <div key={r.id} className="ritem">
                    <div className="rnum">№ {r.num} · Vol. {r.vol} · {r.track}</div>
                    <div className="rtitle">{r.title}</div>
                  </div>
                ))}
              </div>
            </div>

            <div className="cd-tagrow">
              <span className="lbl">Tags</span>
              {p.tags.map(t => <span key={t} className="tag">{t}</span>)}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

function CivicMiniChart({ width = 280, height = 110 } = {}) {
  // Two-line chart: accumulation vs remediation.
  const w = width, h = height;
  const years = 12;
  const accum = [4,8,13,19,26,34,43,53,64,76,89,103];
  const remed = [3,6,9,12,15,18,21,24,27,30,33,36];
  const max = 110;
  const padLeft = 32;
  const padBottom = 24;
  const x = (i) => padLeft + (i*(w-padLeft-16)/(years-1));
  const y = (v) => h - padBottom - (v/max)*(h-padBottom-12);
  const path = (arr) => arr.map((v,i)=>`${i?'L':'M'}${x(i)} ${y(v)}`).join(' ');
  // Y-axis ticks (only when chart is tall enough to show them)
  const showAxis = h >= 160;
  const yTicks = showAxis ? [0, 30, 60, 90] : [];
  return (
    <svg width={w} height={h} style={{display:'block', width:'100%', maxWidth: w + 'px'}} viewBox={`0 0 ${w} ${h}`} preserveAspectRatio="xMidYMid meet">
      {/* gridlines */}
      {yTicks.map(t => (
        <g key={t}>
          <line x1={padLeft} y1={y(t)} x2={w-16} y2={y(t)} stroke={civicTheme.rule} strokeDasharray="2 4"/>
          <text x={padLeft-6} y={y(t)+3} fontFamily="JetBrains Mono" fontSize="9" fill={civicTheme.ink50} textAnchor="end">{t}K</text>
        </g>
      ))}
      <line x1={padLeft} y1={h-padBottom} x2={w-16} y2={h-padBottom} stroke={civicTheme.ink} strokeWidth="0.7"/>
      {/* x-axis labels */}
      {[0,3,6,9,11].map(i => (
        <text key={i} x={x(i)} y={h-padBottom+14} fontFamily="JetBrains Mono" fontSize="9" fill={civicTheme.ink50} textAnchor="middle">{2014+i}</text>
      ))}
      <path d={path(accum)} stroke={civicTheme.highlight} strokeWidth="1.5" fill="none"/>
      <path d={path(remed)} stroke={civicTheme.accent} strokeWidth="1.5" fill="none" strokeDasharray="3 2"/>
      <circle cx={x(years-1)} cy={y(accum[years-1])} r="3" fill={civicTheme.highlight}/>
      <circle cx={x(years-1)} cy={y(remed[years-1])} r="3" fill={civicTheme.accent}/>
      <text x={x(years-1)+8} y={y(accum[years-1])+3} fontFamily="JetBrains Mono" fontSize="10" fill={civicTheme.highlight}>accumulated</text>
      <text x={x(years-1)+8} y={y(remed[years-1])+3} fontFamily="JetBrains Mono" fontSize="10" fill={civicTheme.accent}>remediated</text>
    </svg>
  );
}

function CivicArch() {
  return (
    <div className="civic-arch">
      <div style={{fontFamily:'JetBrains Mono',fontSize:11,letterSpacing:'0.16em',textTransform:'uppercase',color:civicTheme.ink50,marginBottom:14}}>
        The Agentic Operating Model · Reference Architecture
      </div>
      <h1>How the agents are arranged.</h1>
      <p className="lede">Velocity is a layered population of specialized agents. Each agent is accountable to a contract, operates within a defined autonomy budget, and produces artifacts the next layer can verify. The diagram below is the canonical reference. Hover any agent to see throughput.</p>
      <div className="legend">
        <div className="key"><span className="swatch" style={{background:civicTheme.accent}}></span> Autonomous</div>
        <div className="key"><span className="swatch" style={{background:civicTheme.highlight}}></span> Human-gated</div>
        <div className="key"><span className="swatch" style={{background:civicTheme.ok}}></span> Verification</div>
        <div className="key"><span className="swatch" style={{background:civicTheme.ruleStrong}}></span> Data layer</div>
      </div>
      <CivicArchDiagram />
    </div>
  );
}

function CivicArchDiagram() {
  const layers = window.VW.architecture.layers;
  const agents = window.VW.architecture.agents;
  const agentClass = (a) => {
    if (a.cls === 'verifier') return 'verifier';
    if (a.cls === 'human' || a.cls === 'ledger') return 'human';
    return 'auto';
  };
  return (
    <div className="arch-diagram">
      {layers.map((l, idx) => {
        const list = agents.filter(a => a.layer === l.id);
        return (
          <div className="arch-row" key={l.id}>
            <div className="arch-label">
              <div>
                <div className="lbl">{l.label}</div>
                <div className="sub">{l.sub}</div>
              </div>
              <div className="num">L{String(idx+1).padStart(2,'0')}</div>
            </div>
            <div className="arch-agents">
              {list.map(a => (
                <div className={'arch-agent ' + agentClass(a)} key={a.id}>
                  <div className="a-name">{a.label}</div>
                  <div className="a-tp">{a.throughput}</div>
                </div>
              ))}
            </div>
          </div>
        );
      })}
    </div>
  );
}

function CivicApp() {
  const [page, setPage] = React.useState('landing');
  const [paperId, setPaperId] = React.useState('wp-01');
  const openPaper = (id) => { setPaperId(id); setPage('detail'); };
  return (
    <div className="civic">
      <style>{civicCSS}</style>
      <CivicNav page={page} setPage={setPage} />
      <div className="civic-main" key={page}>
        {page === 'landing' && <CivicLanding setPage={setPage} openPaper={openPaper} />}
        {page === 'index' && <CivicIndex openPaper={openPaper} />}
        {page === 'detail' && <CivicDetail paperId={paperId} setPage={setPage} />}
        {page === 'arch' && <CivicArch />}
      </div>
    </div>
  );
}

window.CivicApp = CivicApp;
